nodes.notes:
Gmail - read, send, reply, search, and manage emails.

Actions:
  get_unread - list unread emails. Use for "check my email", "any new emails".
  read - get full email content by ID. Requires message_id from a prior get_unread or search.
  send - send an email. Requires to, subject, and body.
  reply - reply to an email. Requires message_id and body.
  forward - forward an email. Requires message_id and to (recipient email).
  search - search emails by query. Use Gmail syntax like "from:boss", "subject:invoice", "has:attachment".
  mark_read - mark an email as read. Requires message_id.
  trash - move an email to trash. Requires message_id.
  get_labels - list all labels/folders.
  get_thread - get a full email conversation. Requires thread_id from a prior read call.
  add_label - add a label to an email. Requires message_id and label name.
  remove_label - remove a label from an email. Requires message_id and label name.

Rules:
- message_id and thread_id come from prior calls. Never fabricate IDs.
- For send: if user gives a name instead of email, call google_contacts first.
- search uses Gmail query syntax: from:, to:, subject:, has:attachment, is:starred, newer_than:2d, etc.

Chaining:
- "Read my latest email" -> get_unread limit 1 -> read with message_id
- "Reply to that email" -> reply with message_id from context
- "Find invoices from last week" -> search "subject:invoice newer_than:7d"
- "Label that as important" -> add_label with message_id and label "IMPORTANT"
- "Forward that to John" -> forward with message_id and to from google_contacts lookup

---schema
{
  "action": {
    "type": "string",
    "description": "One of: get_unread, read, send, reply, forward, search, mark_read, trash, get_labels, get_thread, add_label, remove_label",
    "required": true
  },
  "message_id": {
    "type": "string",
    "description": "Gmail message ID. For: read, reply, forward, mark_read, trash, add_label, remove_label"
  },
  "thread_id": {
    "type": "string",
    "description": "Gmail thread ID. For: get_thread"
  },
  "to": {
    "type": "string",
    "description": "Recipient email address. For: send, forward"
  },
  "cc": {
    "type": "string",
    "description": "CC recipients, comma-separated. For: send"
  },
  "bcc": {
    "type": "string",
    "description": "BCC recipients, comma-separated. For: send"
  },
  "subject": {
    "type": "string",
    "description": "Email subject line. For: send"
  },
  "body": {
    "type": "string",
    "description": "Email body text. For: send, reply"
  },
  "query": {
    "type": "string",
    "description": "Gmail search query, e.g. from:boss subject:meeting. For: search"
  },
  "label": {
    "type": "string",
    "description": "Label name, e.g. IMPORTANT, Work, Receipts. For: add_label, remove_label"
  },
  "limit": {
    "type": "integer",
    "description": "Max results. Default 10. For: get_unread, search"
  }
}

parameters.jsCode:
// Parse input
let data;
const input = $input.item.json;

if (typeof input.body === 'string') {
  data = JSON.parse(input.body);
} else if (typeof input.body === 'object') {
  data = input.body;
} else {
  data = input;
}

const action = (data.action || '').toLowerCase().trim();
const limit = parseInt(data.limit) || 10;
const message_id = data.message_id || '';
const thread_id = data.thread_id || '';
const to = data.to || '';
const cc = data.cc || '';
const bcc = data.bcc || '';
const subject = data.subject || '';
const body = data.body || data.message || '';
const query = data.query || '';
const label = data.label || '';

if (!action) {
  return [{ json: { error: true, message: 'Action is required. Use one of: get_unread, read, send, reply, search, mark_read, trash, get_labels, get_thread, add_label, remove_label.' } }];
}

// Determine category
const categoryMap = {
  get_unread: 'read',
  read: 'read',
  search: 'read',
  get_thread: 'read',
  get_labels: 'read',
  send: 'write',
  reply: 'write',
  forward: 'write',
  mark_read: 'manage',
  trash: 'manage',
  add_label: 'manage',
  remove_label: 'manage'
};

const category = categoryMap[action] || '';

if (!category) {
  return [{ json: { error: true, message: `Unknown action: ${action}. Use one of: get_unread, read, send, reply, search, mark_read, trash, get_labels, get_thread, add_label, remove_label.` } }];
}

return [{
  json: {
    action,
    category,
    message_id,
    thread_id,
    to,
    cc,
    bcc,
    subject,
    body,
    query,
    label,
    limit
  }
}];

// Format emails for voice
const allItems = $input.all();
const emails = allItems.map(i => i.json).filter(e => e && e.id);

if (!emails || emails.length === 0) {
  return {
    message: "No unread emails.",
    count: 0,
    emails: []
  };
}

// Format emails - Gmail API returns capitalized fields: From, Subject, internalDate
const formatted = emails.map(email => {
  // Get sender name (extract from "Name <email>" format)
  let from = email.From || email.from || 'Unknown';
  const nameMatch = from.match(/^([^<]+)/);
  if (nameMatch) {
    from = nameMatch[1].trim().replace(/"/g, '');
  }

  // Get date from internalDate (milliseconds since epoch)
  const timestamp = email.internalDate || email.date;
  const date = new Date(parseInt(timestamp));
  const now = new Date();
  const diffHours = Math.floor((now - date) / (1000 * 60 * 60));
  let timeAgo = '';
  if (diffHours < 1) {
    const diffMins = Math.floor((now - date) / (1000 * 60));
    timeAgo = diffMins <= 1 ? 'just now' : `${diffMins} minutes ago`;
  } else if (diffHours < 24) {
    timeAgo = diffHours === 1 ? '1 hour ago' : `${diffHours} hours ago`;
  } else {
    const diffDays = Math.floor(diffHours / 24);
    timeAgo = diffDays === 1 ? 'yesterday' : `${diffDays} days ago`;
  }

  return {
    from: from,
    subject: email.Subject || email.subject || '(no subject)',
    snippet: email.snippet || '',
    date: timeAgo,
    id: email.id,
    threadId: email.threadId || ''
  };
});

// Build voice message
let message = '';
if (formatted.length === 1) {
  const e = formatted[0];
  message = `You have one unread email from ${e.from}: ${e.subject}.`;
} else {
  message = `You have ${formatted.length} unread emails. `;
  const summaries = formatted.slice(0, 3).map(e => `${e.from}: ${e.subject}`);
  message += summaries.join('. ') + '.';
  if (formatted.length > 3) {
    message += ` Plus ${formatted.length - 3} more.`;
  }
}

return {
  message: message,
  count: formatted.length,
  emails: formatted
};

const email = $input.item.json;

// Extract fields
let from = email.From || email.from || 'Unknown';
const nameMatch = from.match(/^([^<]+)/);
if (nameMatch) {
  from = nameMatch[1].trim().replace(/"/g, '');
}

const to = email.To || email.to || '';
const subject = email.Subject || email.subject || '(no subject)';
const date = email.Date || email.date || '';
const bodyText = email.textPlain || email.snippet || email.textHtml || '';
const threadId = email.threadId || '';
const messageId = email.id || '';

// Build a body preview (first 500 chars)
let bodyPreview = bodyText;
if (bodyPreview.length > 500) {
  bodyPreview = bodyPreview.substring(0, 500) + '...';
}

const message = `Email from ${from}: ${subject}. ${bodyPreview}`;

return {
  message: message,
  email: {
    from: from,
    to: to,
    subject: subject,
    date: date,
    body: bodyText,
    message_id: messageId,
    thread_id: threadId
  }
};

// Format search results
const allItems = $input.all();
const emails = allItems.map(i => i.json).filter(e => e && e.id);
const query = $('Parse Parameters').item.json.query;

if (!emails || emails.length === 0) {
  return {
    message: `No emails found matching "${query}".`,
    count: 0,
    emails: []
  };
}

const formatted = emails.map(email => {
  let from = email.From || email.from || 'Unknown';
  const nameMatch = from.match(/^([^<]+)/);
  if (nameMatch) {
    from = nameMatch[1].trim().replace(/"/g, '');
  }

  const timestamp = email.internalDate || email.date;
  const date = new Date(parseInt(timestamp));
  const now = new Date();
  const diffHours = Math.floor((now - date) / (1000 * 60 * 60));
  let timeAgo = '';
  if (diffHours < 1) {
    const diffMins = Math.floor((now - date) / (1000 * 60));
    timeAgo = diffMins <= 1 ? 'just now' : `${diffMins} minutes ago`;
  } else if (diffHours < 24) {
    timeAgo = diffHours === 1 ? '1 hour ago' : `${diffHours} hours ago`;
  } else {
    const diffDays = Math.floor(diffHours / 24);
    timeAgo = diffDays === 1 ? 'yesterday' : `${diffDays} days ago`;
  }

  return {
    from: from,
    subject: email.Subject || email.subject || '(no subject)',
    snippet: email.snippet || '',
    date: timeAgo,
    id: email.id,
    threadId: email.threadId || ''
  };
});

let message = '';
if (formatted.length === 1) {
  const e = formatted[0];
  message = `Found 1 email matching "${query}": from ${e.from}, subject: ${e.subject}.`;
} else {
  message = `Found ${formatted.length} emails matching "${query}". `;
  const summaries = formatted.slice(0, 3).map(e => `${e.from}: ${e.subject}`);
  message += summaries.join('. ') + '.';
  if (formatted.length > 3) {
    message += ` Plus ${formatted.length - 3} more.`;
  }
}

return {
  message: message,
  count: formatted.length,
  emails: formatted
};

const response = $input.item.json;
const messages = response.messages || [];

if (!messages.length) {
  return [{ json: { message: 'No messages found in this thread.', error: true } }];
}

const formatted = messages.map(msg => {
  const headers = msg.payload?.headers || [];
  const getHeader = (name) => {
    const h = headers.find(h => h.name.toLowerCase() === name.toLowerCase());
    return h ? h.value : '';
  };

  let from = getHeader('From');
  const nameMatch = from.match(/^([^<]+)/);
  if (nameMatch) from = nameMatch[1].trim().replace(/"/g, '');

  return {
    from: from,
    to: getHeader('To'),
    subject: getHeader('Subject'),
    date: getHeader('Date'),
    snippet: msg.snippet || '',
    id: msg.id
  };
});

const participants = [...new Set(formatted.map(m => m.from).filter(Boolean))];
const subject = formatted.find(m => m.subject)?.subject || '(no subject)';
const latest = formatted[formatted.length - 1];

let message = `Thread with ${formatted.length} message${formatted.length > 1 ? 's' : ''}`;
if (participants.length) message += ` between ${participants.join(' and ')}`;
message += `. Subject: ${subject}.`;
if (latest.snippet) message += ` Latest from ${latest.from}: ${latest.snippet}`;

return {
  message,
  thread_id: response.id || $('Parse Parameters').item.json.thread_id,
  count: formatted.length,
  messages: formatted
};

const response = $input.item.json;
const labels = response.labels || [];

if (!labels || labels.length === 0) {
  return {
    message: 'No labels found.',
    labels: []
  };
}

const formatted = labels.map(l => ({
  id: l.id,
  name: l.name,
  type: l.type || 'user'
}));

// Separate system and user labels
const systemLabels = formatted.filter(l => l.type === 'system').map(l => l.name);
const userLabels = formatted.filter(l => l.type === 'user').map(l => l.name);

let message = `You have ${formatted.length} labels. `;
if (userLabels.length > 0) {
  message += `Custom labels: ${userLabels.join(', ')}. `;
}
message += `System labels: ${systemLabels.join(', ')}.`;

return {
  message: message,
  count: formatted.length,
  labels: formatted
};

// Validate send parameters
const data = $input.item.json;

if (!data.to) {
  return [{ json: { error: true, message: 'Recipient email address (to) is required.' } }];
}
if (!data.subject) {
  return [{ json: { error: true, message: 'Email subject is required.' } }];
}
if (!data.body) {
  return [{ json: { error: true, message: 'Email body/message is required.' } }];
}

return [{ json: data }];

// Format success response for voice
const result = $input.item.json;
const validated = $('Validate Send').item.json;
const to = validated.to || '';
const subject = validated.subject || '';

// Extract recipient name from email if possible
let recipientName = to;
if (to.includes('@')) {
  recipientName = to.split('@')[0].replace(/[._]/g, ' ');
}

const message = `Done. Email sent to ${recipientName} with subject: ${subject}.`;

return {
  message: message,
  sent: true,
  to: to,
  subject: subject,
  messageId: result.id
};

// Validate reply parameters
const data = $input.item.json;

if (!data.message_id) {
  return [{ json: { error: true, message: 'message_id is required for reply. Get it from a prior read or get_unread call.' } }];
}
if (!data.body) {
  return [{ json: { error: true, message: 'Reply body/message is required.' } }];
}

return [{ json: data }];

const result = $input.item.json;
const messageId = result.id || $('Validate Reply').item.json.message_id || '';

return {
  message: 'Reply sent.',
  sent: true,
  message_id: messageId
};

const messageId = $('Parse Parameters').item.json.message_id || '';

return {
  message: 'Email marked as read.',
  message_id: messageId
};

const messageId = $('Parse Parameters').item.json.message_id || '';

return {
  message: 'Email moved to trash.',
  message_id: messageId
};

const response = $input.item.json;
const labels = response.labels || [];
const params = $('Parse Parameters').item.json;
const labelName = params.label;
const messageId = params.message_id;

if (!labelName) {
  return [{ json: { error: true, message: 'Label name is required for add_label.' } }];
}
if (!messageId) {
  return [{ json: { error: true, message: 'message_id is required for add_label.' } }];
}

// Find label by name (case-insensitive)
const match = labels.find(l => l.name.toLowerCase() === labelName.toLowerCase());

if (!match) {
  return [{ json: { error: true, message: `Label "${labelName}" not found. Use get_labels to see available labels.` } }];
}

return [{
  json: {
    message_id: messageId,
    label_id: match.id,
    label_name: match.name
  }
}];

const params = $('Find Label Add').item.json;

return {
  message: `Label "${params.label_name}" added to email.`,
  message_id: params.message_id,
  label: params.label_name
};

const response = $input.item.json;
const labels = response.labels || [];
const params = $('Parse Parameters').item.json;
const labelName = params.label;
const messageId = params.message_id;

if (!labelName) {
  return [{ json: { error: true, message: 'Label name is required for remove_label.' } }];
}
if (!messageId) {
  return [{ json: { error: true, message: 'message_id is required for remove_label.' } }];
}

// Find label by name (case-insensitive)
const match = labels.find(l => l.name.toLowerCase() === labelName.toLowerCase());

if (!match) {
  return [{ json: { error: true, message: `Label "${labelName}" not found. Use get_labels to see available labels.` } }];
}

return [{
  json: {
    message_id: messageId,
    label_id: match.id,
    label_name: match.name
  }
}];

const params = $('Find Label Remove').item.json;

return {
  message: `Label "${params.label_name}" removed from email.`,
  message_id: params.message_id,
  label: params.label_name
};

const errorData = $input.item.json;

// If it's already a formatted error from a Code node
if (errorData.error === true && errorData.message) {
  return { message: errorData.message, error: true };
}

// Otherwise it's from an n8n node error output
let errorMsg = errorData.message || errorData.error || 'Unknown error';

if (typeof errorMsg === 'object') {
  errorMsg = errorMsg.message || JSON.stringify(errorMsg);
}

// Make error voice-friendly
if (errorMsg.includes('authorization') || errorMsg.includes('token') || errorMsg.includes('invalid_grant')) {
  errorMsg = 'Gmail authentication failed. Please re-authorize the Gmail connection.';
} else if (errorMsg.includes('rate limit') || errorMsg.includes('429')) {
  errorMsg = 'Gmail rate limit reached. Try again in a few minutes.';
} else if (errorMsg.includes('404') || errorMsg.includes('Not Found')) {
  errorMsg = 'Email not found. The message_id may be invalid or the email was deleted.';
} else if (errorMsg.includes('400') || errorMsg.includes('Bad Request')) {
  errorMsg = 'Bad request - please check your parameters.';
} else if (errorMsg.includes('ECONNREFUSED') || errorMsg.includes('ETIMEDOUT')) {
  errorMsg = 'Cannot connect to Gmail. Check your internet connection.';
}

return { message: 'Gmail error: ' + errorMsg, error: true };

const data = $input.item.json;

if (!data.message_id) {
  return [{ json: { error: true, message: 'message_id is required for forward. Get it from a prior read or get_unread call.' } }];
}
if (!data.to) {
  return [{ json: { error: true, message: 'Recipient email address (to) is required for forward.' } }];
}

return [{ json: data }];

const original = $input.item.json;
const params = $('Parse Parameters').item.json;

// Get original details
const origFrom = original.From || original.from || 'Unknown';
const origTo = original.To || original.to || '';
const origSubject = original.Subject || original.subject || '(no subject)';
const origDate = original.Date || original.date || '';
const origBody = original.text || original.snippet || '';

// Build forwarded subject
const subject = origSubject.startsWith('Fwd:') ? origSubject : `Fwd: ${origSubject}`;

// Build forwarded body
const forwardHeader = `---------- Forwarded message ----------\nFrom: ${origFrom}\nDate: ${origDate}\nSubject: ${origSubject}\nTo: ${origTo}\n\n`;

const body = forwardHeader + origBody;

return [{ json: { to: params.to, subject, body } }];

const result = $input.item.json;
const params = $('Parse Parameters').item.json;
const to = params.to || '';

let recipientName = to;
if (to.includes('@')) {
  recipientName = to.split('@')[0].replace(/[._]/g, ' ');
}

return {
  message: `Email forwarded to ${recipientName}.`,
  forwarded: true,
  to: to,
  messageId: result.id
};
